<?php
namespace App\Http\Controllers\Api;use App\Http\Controllers\Controller;use App\Http\Resources\ApiResponse;use App\Http\Resources\OrderResource;use App\Models\Order;use Illuminate\Http\JsonResponse;use Illuminate\Support\Facades\Auth;class OrderController extends Controller{public function index(): JsonResponse{$orders=Order::with(['items.product','delivery'])->where('user_id',Auth::id())->latest()->paginate(20);return new ApiResponse(OrderResource::collection($orders));}public function store(\App\Http\Requests\OrderStoreRequest $request): JsonResponse{$cartItems=Auth::user()->cartItems->load('product');if($cartItems->isEmpty()){return new ApiResponse(null,'Cart is empty',422);}$totalAmount=$cartItems->sum(fn($item)=>$item->quantity*$item->product->price);$order=Order::create(['user_id'=>Auth::id(),'total_amount'=>$totalAmount,'delivery_address'=>$request->delivery_address,'cod_amount'=>$request->cod_amount??0,...$request->validated(),]);foreach($cartItems as $item){$order->items()->create(['product_id'=>$item->product_id,'quantity'=>$item->quantity,'price'=>$item->product->price,]);}$order->load('items.product');return new ApiResponse(new OrderResource($order),'Order created successfully',201);}public function show(string $id): JsonResponse{$order=Order::with(['items.product','delivery','user'])->findOrFail($id);if($order->user_id!==Auth::id()&&!Auth::user()->isAdmin()){return new ApiResponse(null,'Forbidden',403);}return new ApiResponse(new OrderResource($order));}public function updateStatus(\App\Http\Requests\OrderStatusRequest $request,string $id): JsonResponse{$order=Order::findOrFail($id);if($order->user_id!==Auth::id()&&!Auth::user()->isAdmin()){return new ApiResponse(null,'Forbidden',403);}$order->update($request->validated());return new ApiResponse(new OrderResource($order->fresh()->load('items.product')),'Order status updated');}}